// Cal.com v2 webhook: data is under items[0].json.body
const root = items[0].json;
const body = root.body || root;
const triggerEvent = body.triggerEvent || body.eventType || '';
const p = body.payload || body;
const attendee = (p.attendees && p.attendees[0]) || p.invitee || {};
// LinkedIn URL can be in metadata (e.g. passed via booking-intake custom field)
const linkedin_url = (p.metadata && (p.metadata.linkedinUrl || p.metadata.linkedin_url)) ||
                     (attendee.metadata && (attendee.metadata.linkedinUrl || attendee.metadata.linkedin_url)) ||
                     '';
return [{ json: {
  triggerEvent,
  email: (attendee.email || '').toLowerCase(),
  name: attendee.name || '',
  linkedin_url: linkedin_url.toLowerCase(),
  starts_at: p.startTime || p.start_time || (p.event && p.event.start_time) || '',
  event_uri: p.uid || p.id || (p.event && (p.event.uri || p.event.id)) || '',
  reschedule_uid: p.rescheduleUid || p.reschedule_uid || ''
}}];
